const LANG_FULL = { en: 'English', 'zh-CN': '简体中文', 'zh-TW': '繁體中文', ja: '日本語' };
// A clean line-art globe icon for the switcher (matches the nav/topbar icons).
const GLOBE_SVG = '<svg viewBox="0 0 24 24" width="17" height="17" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="9"/><path d="M3 12h18"/><path d="M12 3c2.6 2.7 2.6 15.3 0 18M12 3c-2.6 2.7-2.6 15.3 0 18"/></svg>';
// Small flag glyphs (simple inline SVG, clipped to a rounded rect by .flag) for
// the region each language is mainly spoken in. English uses the globe icon.
const FLAG_SVG = {
  'zh-CN': '<svg viewBox="0 0 24 18" preserveAspectRatio="xMidYMid slice"><rect width="24" height="18" fill="#de2910"/><g fill="#ffde00" font-family="serif" text-anchor="middle" dominant-baseline="central"><text x="5" y="5.2" font-size="8">★</text><text x="10.5" y="2.1" font-size="3.2">★</text><text x="12.6" y="4.5" font-size="3.2">★</text><text x="12.6" y="7.6" font-size="3.2">★</text><text x="10.5" y="10" font-size="3.2">★</text></g></svg>',
  'zh-TW': '<svg viewBox="0 0 24 18" preserveAspectRatio="xMidYMid slice"><rect width="24" height="18" fill="#fe0000"/><rect width="12" height="9" fill="#000095"/><circle cx="6" cy="4.5" r="2.7" fill="#fff"/><circle cx="6" cy="4.5" r="1.5" fill="#000095"/></svg>',
  'ja': '<svg viewBox="0 0 24 18" preserveAspectRatio="xMidYMid slice"><rect width="24" height="18" fill="#fff"/><circle cx="12" cy="9" r="5.2" fill="#bc002d"/></svg>',
};
function langIcon(code) {
  return code === 'en' ? `<span class="flag globe">${GLOBE_SVG}</span>` : `<span class="flag">${FLAG_SVG[code] || ''}</span>`;
}

function curLang() { return window.__LANG__ || 'en'; }

// Translate a key (with optional {var} substitution); falls back to English,
// then to the key itself.
function tr(key, vars) {
  const d = I18N[curLang()] || I18N.en;
  let s = (d && d[key] != null) ? d[key] : (I18N.en[key] != null ? I18N.en[key] : key);
  if (vars) for (const k in vars) s = s.split('{' + k + '}').join(vars[k]);
  return s;
}

// Map a raw error string to a localized message when it carries a stable code
// marker (`ERR_CODE:<code>` → `err.<code>`); otherwise return it unchanged.
// Capability ops (docker/nginx/mysql) emit fixed validation errors this way.
function codeMsg(s) {
  if (typeof s === 'string') {
    const m = s.match(/^ERR_CODE:(.+)$/);
    if (m) { const k = 'err.' + m[1]; const t = tr(k); return t !== k ? t : m[1]; }
  }
  return s;
}

// Map a progress-log line that carries a localizable MSG marker
// (`\x1eMSG\x1e<code>[\x1earg…]`) to a translated string with positional
// {0},{1}… substitution. An arg prefixed with `@` is itself a translation key.
// Plain command-output lines pass through unchanged.
function msgLine(s) {
  if (typeof s === 'string' && s.indexOf('\x1eMSG\x1e') === 0) {
    const p = s.split('\x1e'); // ['', 'MSG', code, arg0, arg1, …]
    const code = p[2];
    const vars = {};
    for (let i = 3; i < p.length; i++) { let a = p[i]; if (a && a[0] === '@') a = tr(a.slice(1)); vars[i - 3] = a; }
    const k = 'msg.' + code;
    const t = tr(k, vars);
    return t !== k ? t : code;
  }
  return s;
}

// Map a server error response to a localized message. The server returns a
// stable `code` for fixed/enumerable errors (auth, settings, validation…);
// we translate it via `err.<code>`. Falls back to the server-provided `error`
// string (which may itself carry an `ERR_CODE:` marker for capability ops).
function srvMsg(body) {
  if (body && typeof body === 'object' && body.code) {
    const k = 'err.' + body.code;
    const m = tr(k);
    if (m !== k) return m;
  }
  const raw = (body && (body.error || (typeof body === 'string' ? body : ''))) || '';
  return codeMsg(raw);
}

// Translate static nodes: text via data-i18n, placeholder via data-i18n-ph,
// title via data-i18n-title.
function applyI18n(root) {
  const r = root || document;
  r.querySelectorAll('[data-i18n]').forEach((el) => { el.textContent = tr(el.getAttribute('data-i18n')); });
  r.querySelectorAll('[data-i18n-ph]').forEach((el) => { el.setAttribute('placeholder', tr(el.getAttribute('data-i18n-ph'))); });
  r.querySelectorAll('[data-i18n-title]').forEach((el) => { el.setAttribute('title', tr(el.getAttribute('data-i18n-title'))); });
}

// Persist a manual language choice and reload so the whole UI re-renders in it.
function setLang(code) {
  if (!I18N[code] || code === curLang()) return;
  try { localStorage.setItem('dn7_lang', code); } catch (e) {}
  location.reload();
}

// Language switcher popup anchored to the topbar button.
function toggleLangMenu() {
  let pop = document.querySelector('.lang-pop');
  if (pop) { pop.remove(); return; }
  const btn = document.getElementById('langBtn');
  if (!btn) return;
  pop = document.createElement('div');
  pop.className = 'selx-pop lang-pop';
  ['en', 'zh-CN', 'zh-TW', 'ja'].forEach((code) => {
    const o = document.createElement('div');
    o.className = 'selx-opt lang-opt' + (code === curLang() ? ' sel' : '');
    o.innerHTML = `${langIcon(code)}<span>${LANG_FULL[code]}</span>`;
    o.addEventListener('mousedown', (e) => { e.preventDefault(); pop.remove(); setLang(code); });
    pop.appendChild(o);
  });
  document.body.appendChild(pop);
  const r = btn.getBoundingClientRect();
  pop.style.minWidth = '120px';
  pop.style.left = Math.max(8, r.right - 120) + 'px';
  pop.style.top = (r.bottom + 4) + 'px';
  const close = (e) => { if (!e.target.closest('.lang-pop') && e.target.id !== 'langBtn') { pop.remove(); document.removeEventListener('mousedown', close, true); } };
  setTimeout(() => document.addEventListener('mousedown', close, true), 0);
}

// Initialize: translate the static DOM, label the switcher, then reveal.
(function initI18n() {
  applyI18n(document);
  const btn = document.getElementById('langBtn');
  if (btn) {
    btn.innerHTML = GLOBE_SVG;
    btn.title = tr('lang.name') + ' · ' + (LANG_FULL[curLang()] || '');
    btn.onclick = toggleLangMenu;
  }
  document.documentElement.setAttribute('data-i18n-ready', '1');
})();
